            # Client_body_buffer_size and client_max_body_size might need tuning.
            client_body_buffer_size 1m;
            client_max_body_size 10m;
            lua_need_request_body on;
            lua_check_client_body_buffered on;

            content_by_lua_block {
                -- IMPORTANT: Ensure LuaXML is installed and accessible to OpenResty.
                -- You can install it via LuaRocks: 'luarocks install luaxml'
