                local parser = LuaXML.parser.new()

                -- Read the request body
                ngx.req.read_body()
                local xml_body = ngx.req.get_body()

                if not xml_body then
                    ngx.status = 400
                    ngx.header["Content-Type"] = "text/xml"
                    ngx.say([[
<soapenv:Envelope xmlns:soapenv="http://schemas.xmlsoap.org/soap/envelope/">
    <soapenv:Body>
        <soapenv:Fault>
            <faultcode>soapenv:Client</faultcode>
            <faultstring>Request body is empty or could not be read.</faultstring>
        </soapenv:Fault>
    </soapenv:Body>
</soapenv:Envelope>
]])
                    return
                end

                -- Parse the XML body
                local ok, doc = parser:parse(xml_body)

                if not ok then
                    ngx.status = 400
                    ngx.header["Content-Type"] = "text/xml"
                    ngx.say([[
<soapenv:Envelope xmlns:soapenv="http://schemas.xmlsoap.org/soap/envelope/">
    <soapenv:Body>
        <soapenv:Fault>
            <faultcode>soapenv:Client</faultcode>
            <faultstring>Error parsing XML: ]] .. ngx.escape_uri(tostring(doc)) .. [[</faultstring>
        </soapenv:Fault>
    </soapenv:Body>
</soapenv:Envelope>
]])
                    ngx.log(ngx.ERR, "XML parsing error: ", tostring(doc))
                    return
