                local body_node = doc:find("soapenv:Body")
                if not body_node then
                    ngx.status = 400
                    ngx.header["Content-Type"] = "text/xml"
                    ngx.say([[
<soapenv:Envelope xmlns:soapenv="http://schemas.xmlsoap.org/soap/envelope/">
    <soapenv:Body>
        <soapenv:Fault>
            <faultcode>soapenv:Client</faultcode>
            <faultstring>Missing SOAP Body element.</faultstring>
        </soapenv:Fault>
    </soapenv:Body>
</soapenv:Envelope>
