                    ngx.header["Content-Type"] = "text/xml"
                    ngx.say([[
<soapenv:Envelope xmlns:soapenv="http://schemas.xmlsoap.org/soap/envelope/">
    <soapenv:Body>
        <soapenv:Fault>
            <faultcode>soapenv:Client</faultcode>
            <faultstring>Missing GetUserInfo operation in SOAP Body.</faultstring>
        </soapenv:Fault>
    </soapenv:Body>
</soapenv:Envelope>
]])
                    return
                end

                -- Access elements and their values
                local user_id_node = get_user_info_node:find("ser:UserId")
                local username_node = get_user_info_node:find("ser:Username")
                local email_node = get_user_info_node:find("ser:Email")
                local description_node = get_user_info_node:find("ser:Description")
                local flex_field_node = get_user_info_node:find("ser:FlexField")

                local user_id = user_id_node and user_id_node.value or "N/A"
                local username = username_node and username_node.value or "N/A"
                local email = email_node and email_node.value or "N/A"
                local description = description_node and description_node.value or "N/A"
