                ngx.header["Content-Type"] = "text/xml; charset=utf-8"
                ngx.status = 200

                ngx.say([[
<soapenv:Envelope xmlns:soapenv="http://schemas.xmlsoap.org/soap/envelope/"
                  xmlns:ser="http://example.com/service">
   <soapenv:Body>
      <ser:GetUserInfoResponse>
         <ser:Status>Success</ser:Status>
